/**
 * SOP (Standard Operating Procedure) template for every role we work.
 *
 * The list is intentionally hard-coded — it's the company-wide playbook,
 * NOT a per-job checklist generated by the kickoff prompt. Checked-state
 * persists per vacante via hiring.tasks rows marked with
 * `<!-- sop:v1 | item: ITEM_ID -->`; missing items are seeded the first
 * time the SOP tab opens for a vacante (see paquete/page.tsx).
 *
 * Ordering, indent, and phase grouping below ARE the SOP. If we want to
 * add a step, remove a step, or rename one, this file is the source of
 * truth. Existing hiring.tasks rows with item IDs no longer in the
 * template become orphans (not rendered, harmless).
 */

export type SopPhaseKey =
  | "admin"
  | "kickoff"
  | "calibration"
  | "sourcing"
  | "reports"
  | "interviews"
  | "preoffer"
  | "offer";

export type SopItem = {
  /** Stable ID — DO NOT change once shipped; it's the join key against
   *  the hiring.tasks rows in DB. New steps need a NEW id. */
  id: string;
  phase: SopPhaseKey;
  /** 0 = top-level step. 1 = sub-step (rendered indented). */
  indent: 0 | 1;
  /** Title shown in the recruiter UI. Localized lookups happen in the
   *  React component via t(`sop.items.${id}`). */
  labelEs: string;
  labelEn: string;
};

export const SOP_PHASES: ReadonlyArray<{
  key: SopPhaseKey;
  labelEs: string;
  labelEn: string;
}> = [
  { key: "admin", labelEs: "Admin", labelEn: "Admin" },
  { key: "kickoff", labelEs: "Kickoff", labelEn: "Kickoff" },
  { key: "calibration", labelEs: "Calibración", labelEn: "Calibration" },
  { key: "sourcing", labelEs: "Sourcing & Outreach", labelEn: "Sourcing & Outreach" },
  { key: "reports", labelEs: "Candidate Reports & Envío", labelEn: "Candidate Reports & Submission" },
  { key: "interviews", labelEs: "Entrevistas con cliente", labelEn: "Client Interviews" },
  { key: "preoffer", labelEs: "Pre-oferta", labelEn: "Pre-offer" },
  { key: "offer", labelEs: "Oferta y Placement", labelEn: "Offer & Placement" },
] as const;

