/** Marker comment we write into hiring.tasks.body so we can recover the
 *  item id later. Kept in sync with the regex in paquete/page.tsx. */
export const SOP_MARKER_PREFIX = "sop:v1";

export function sopMarker(itemId: string): string {
  return `<!-- ${SOP_MARKER_PREFIX} | item: ${itemId} -->`;
}
